import WidgetKit
import SwiftUI
import AppIntents

struct EventEntry: TimelineEntry {
    let date: Date
    let eventTitle: String
}

struct EventProvider: TimelineProvider {
    func placeholder(in context: Context) -> EventEntry {
        EventEntry(date: Date(), eventTitle: "No Events")
    }
    func getSnapshot(in context: Context, completion: @escaping (EventEntry) -> ()) {
        completion(EventEntry(date: Date(), eventTitle: "No Events"))
    }
    func getTimeline(in context: Context, completion: @escaping (Timeline<EventEntry>) -> ()) {
        let entry = EventEntry(date: Date(), eventTitle: "Team Meeting")
        let timeline = Timeline(entries: [entry], policy: .atEnd)
        completion(timeline)
    }
}

struct EventWidgetEntryView: View {
    var entry: EventProvider.Entry
    var body: some View {
        Text(entry.eventTitle)
            .font(.headline)
    }
}

@main
struct EventWidget: Widget {
    let kind: String = "EventWidget"
    var body: some WidgetConfiguration {
        StaticConfiguration(kind: kind, provider: EventProvider()) { entry in
            EventWidgetEntryView(entry: entry)
        }
        .configurationDisplayName("Next Event")
        .description("Shows your next calendar event.")
        .supportedFamilies([.accessoryRectangular, .accessoryInline])
    }
}

import SwiftUI

@Observable
class SettingsModel {
    var darkMode: Bool = false
    var fontSize: Double = 14
}

struct SettingsView: View {
    @State private var model = SettingsModel()
    var body: some View {
        Toggle("Dark Mode", isOn: $model.darkMode)
        Slider(value: $model.fontSize, in: 10...24, label: { Text("Font Size") })
    }
}

import SwiftUI
import RealityKit

struct FloatingTextImmersiveSpace: ImmersiveSpace {
    var body: some ImmersiveSpaceContent {
        RealityView { content in
            let textMesh = MeshResource.generateText("Hello, visionOS!", extrusionDepth: 0.02, font: .systemFont(ofSize: 0.1))
            let textEntity = ModelEntity(mesh: textMesh)
            let anchor = AnchorEntity(world: [0, 1, -1])
            anchor.addChild(textEntity)
            content.add(anchor)
        }
    }
}

@main
struct MyImmersiveApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
        .immersiveSpace(id: "floatingText") {
            FloatingTextImmersiveSpace()
        }
    }
}

struct ContentView: View {
    var body: some View {
        Text("Welcome to visionOS 26!")
    }
}

import SwiftUI

struct TVListView: View {
    let items = ["Movie 1", "Movie 2", "Movie 3"]
    @State private var selected: String?
    var body: some View {
        List(items, id: \.self, selection: $selected) { item in
            Text(item)
                .focused($selected, equals: item)
        }
    }
}

@main
struct TVApp: App {
    var body: some Scene {
        WindowGroup {
            TVListView()
        }
    }
}

